+        let stdin = child
+            .stdin
+            .take()
+            .ok_or_else(|| Error::config("RPC subprocess stdin is not piped"))?;
+        let stdout = child
+            .stdout
+            .take()
+            .ok_or_else(|| Error::config("RPC subprocess stdout is not piped"))?;
+
+        Ok(Self {
+            child,
+            stdin: BufWriter::new(stdin),
+            stdout: BufReader::new(stdout),
+            next_request_id: 1,
