+    pub fn shutdown(&mut self) -> Result<()> {
+        if self
+            .child
+            .try_wait()
+            .map_err(|err| Error::Io(Box::new(err)))?
+            .is_none()
+        {
+            self.child.kill().map_err(|err| Error::Io(Box::new(err)))?;
+        }
+        let _ = self.child.wait();
+        Ok(())
+    }
