+fn rpc_error_from_response(response: &Value, command: &str) -> Error {
+    let error = response
+        .get("error")
+        .and_then(Value::as_str)
+        .unwrap_or("RPC command failed");
+    Error::api(format!("RPC {command} failed: {error}"))
