+            tool_call,
+            ..
+        } => Some(StreamEvent::ToolCallEnd {
+            content_index: *content_index,
+            tool_call: tool_call.clone(),
+        }),
+        AME::Done { reason, message } => Some(StreamEvent::Done {
+            reason: *reason,
+            message: (**message).clone(),
+        }),
+        AME::Error { reason, error } => Some(StreamEvent::Error {
+            reason: *reason,
+            error: (**error).clone(),
+        }),
